        Criterion,
        RequirementGroup,
        Requirement
    }.AsReadOnly();

    /// <summary>
    /// Get metadata for a specific entity by name
    /// </summary>
    public static EntityMetadata? GetEntityMetadata(string entityName) => entityName switch
    {
        "Organization" => Organization,
        "Tender" => Tender,
        "TenderItem" => TenderItem,
        "Bid" => Bid,
        "BidItem" => BidItem,
        "Award" => Award,
        "ContractChangeRationaleType" => ContractChangeRationaleType,
        "Contract" => Contract,
        "TenderPlan" => TenderPlan,
        "Document" => Document,
        "Milestone" => Milestone,
        "Criterion" => Criterion,
        "RequirementGroup" => RequirementGroup,
        "Requirement" => Requirement,
        _ => null
    };

    #endregion
}
